// src/components/MisinformationChecker.js
import React, { useState } from "react";
import axios from "axios";

const API_URL = "http://127.0.0.1:5000"; // Your Flask Backend URL

function MisinformationChecker() {
  const [text, setText] = useState("");
  const [result, setResult] = useState(null);
  const [error, setError] = useState("");
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (event) => {
    event.preventDefault();
    if (text.length < 50) {
      setError(
        "Please paste a full article or text of at least 50 characters for analysis."
      );
      return;
    }

    setIsLoading(true);
    setError("");
    setResult(null);

    try {
      // Send the text in a JSON body to the misinformation endpoint
      const response = await axios.post(
        `${API_URL}/predict/misinformation`,
        { text },
        {
          headers: {
            "Content-Type": "application/json",
          },
        }
      );

      // The expected Flask response structure is {verdict, confidence_score, summary}
      if (response.data.result === "error") {
        setError(`API Error: ${response.data.message}`);
      } else {
        setResult(response.data);
      }
    } catch (err) {
      // This catches network errors or issues with the Gemini API key
      setError(
        `Network or Server Error. Check your Gemini API key in api_utils.py.`
      );
      console.error("Error:", err);
    } finally {
      setIsLoading(false);
    }
  };

  const getVerdictStyle = (verdict) => {
    switch (verdict) {
      case "FAKE":
        return {
          color: "#e74c3c",
          backgroundColor: "#fbe2e1",
          border: "2px solid #e74c3c",
        };
      case "MISLEADING":
        return {
          color: "#f39c12",
          backgroundColor: "#fef3e3",
          border: "2px solid #f39c12",
        };
      case "REAL":
        return {
          color: "#2ecc71",
          backgroundColor: "#e2fbe8",
          border: "2px solid #2ecc71",
        };
      default:
        return {};
    }
  };

  return (
    <div style={{ maxWidth: "800px", margin: "auto" }}>
      <h2>📰 Misinformation Checker (Gemini NLP)</h2>
      <p>
        Paste a news article, social media post, or large block of text to
        assess its veracity.
      </p>

      <form
        onSubmit={handleSubmit}
        style={{ display: "flex", flexDirection: "column", gap: "15px" }}
      >
        <textarea
          rows="10"
          value={text}
          onChange={(e) => setText(e.target.value)}
          placeholder="Paste your text here for forensic analysis (min 50 chars)..."
          style={{
            padding: "10px",
            border: "1px solid #ccc",
            borderRadius: "5px",
            fontSize: "1em",
          }}
        />
        <button
          type="submit"
          disabled={isLoading || text.length < 50}
          style={{
            padding: "10px 20px",
            backgroundColor: "#9b59b6",
            color: "white",
            border: "none",
            borderRadius: "5px",
            cursor: "pointer",
            opacity: isLoading || text.length < 50 ? 0.6 : 1,
          }}
        >
          {isLoading
            ? "Analyzing with Gemini..."
            : "Analyze for Misinformation"}
        </button>
      </form>

      {error && <p style={{ color: "red", marginTop: "20px" }}>{error}</p>}

      {result && (
        <div
          style={{
            marginTop: "30px",
            padding: "20px",
            border: "1px solid #ddd",
            borderRadius: "8px",
            background: "#fff",
          }}
        >
          <h3>Gemini Analysis Result:</h3>
          <div
            style={{
              ...getVerdictStyle(result.verdict),
              padding: "15px",
              borderRadius: "5px",
              marginBottom: "15px",
              fontWeight: "bold",
            }}
          >
            <h4 style={{ margin: 0 }}>
              VERDICT: {result.verdict || "UNKNOWN"}
            </h4>
            <p style={{ margin: "5px 0 0 0", fontSize: "0.9em" }}>
              Confidence: {(result.confidence_score * 100).toFixed(2)}%
            </p>
          </div>
          <p>
            <strong>Summary:</strong>{" "}
            {result.summary || "No detailed summary provided."}
          </p>
        </div>
      )}
    </div>
  );
}

export default MisinformationChecker;
